 },
 0));

params.push_back(std::make_unique<juce::AudioParameterFloat>(
 juce::ParameterID { "sensitivity", 1 },
 "Sensitivity",
 juce::NormalisableRange<float> { 0.0f, 1.0f, 0.01f },
